import { useState, useEffect, useRef, useCallback } from "react";
import { Chart, ArcElement, Tooltip, Legend } from "chart.js";
import {
  LayoutDashboard, ArrowLeftRight, BarChart2, Wallet, Settings,
  TrendingUp, TrendingDown, Sparkles, Plus, RotateCcw,
  ChevronUp, ChevronDown, ChevronsUpDown, CircleDollarSign
} from "lucide-react";

Chart.register(ArcElement, Tooltip, Legend);

const ACCENT = "#F59E0B";
const CAT_COLORS = {
  makanan: "#F59E0B", transport: "#06B6D4", hiburan: "#8B5CF6",
  perumahan: "#3B82F6", belanja: "#EC4899", kesehatan: "#10B981", income: "#22C55E",
};
const CAT_LABELS = {
  makanan: "Makanan", transport: "Transportasi", hiburan: "Hiburan",
  perumahan: "Perumahan", belanja: "Belanja", kesehatan: "Kesehatan", income: "Pemasukan",
};

const TRANSACTIONS = [
  { id: 1, date: "2025-05-15", desc: "Alfamart Batam Center", cat: "makanan", amount: -145000 },
  { id: 2, date: "2025-05-15", desc: "Gaji Bulan Mei", cat: "income", amount: 8500000 },
  { id: 3, date: "2025-05-14", desc: "Grab — Sekupang ke Nagoya", cat: "transport", amount: -28000 },
  { id: 4, date: "2025-05-14", desc: "Netflix Premium", cat: "hiburan", amount: -75000 },
  { id: 5, date: "2025-05-13", desc: "Sewa Apartemen Mei", cat: "perumahan", amount: -2500000 },
  { id: 6, date: "2025-05-13", desc: "Shopee — Sepatu Sneakers", cat: "belanja", amount: -450000 },
  { id: 7, date: "2025-05-12", desc: "Klinik Bida Batam", cat: "kesehatan", amount: -150000 },
  { id: 8, date: "2025-05-12", desc: "Freelance Design Project", cat: "income", amount: 1500000 },
  { id: 9, date: "2025-05-11", desc: "GrabFood — Nasi Padang", cat: "makanan", amount: -52000 },
  { id: 10, date: "2025-05-10", desc: "Spotify Premium", cat: "hiburan", amount: -54906 },
  { id: 11, date: "2025-05-10", desc: "Ojek Online Kerja", cat: "transport", amount: -18000 },
  { id: 12, date: "2025-05-09", desc: "Superindo Batam", cat: "makanan", amount: -210000 },
  { id: 13, date: "2025-05-08", desc: "Dividen Saham", cat: "income", amount: 350000 },
  { id: 14, date: "2025-05-07", desc: "Apotik K-24", cat: "kesehatan", amount: -45000 },
  { id: 15, date: "2025-05-07", desc: "Tokopedia — Charger Laptop", cat: "belanja", amount: -185000 },
];

const fmtIDR = (n) => {
  const abs = Math.abs(n);
  const s = new Intl.NumberFormat("id-ID", { style: "currency", currency: "IDR", minimumFractionDigits: 0 }).format(abs);
  return (n < 0 ? "- " : "") + s;
};
const fmtDate = (d) => new Date(d).toLocaleDateString("id-ID", { day: "numeric", month: "short", year: "numeric" });

const CSS = `
* { box-sizing: border-box; margin: 0; padding: 0; }
:root { --acc: ${ACCENT}; }
.pf-wrap { display: flex; min-height: 780px; background: var(--color-background-tertiary); font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
.pf-sidebar { width: 216px; min-width: 216px; background: var(--color-background-primary); border-right: 0.5px solid var(--color-border-tertiary); display: flex; flex-direction: column; padding: 1.25rem 0; position: sticky; top: 0; height: 780px; overflow: hidden; }
.pf-main { flex: 1; min-width: 0; padding: 1.75rem; overflow-y: auto; }
.nav-item { display: flex; align-items: center; gap: 9px; padding: 0.55rem 1.1rem; cursor: pointer; font-size: 13.5px; color: var(--color-text-secondary); border-left: 2px solid transparent; transition: all 0.15s; }
.nav-item:hover { background: var(--color-background-secondary); color: var(--color-text-primary); }
.nav-item.act { border-left: 2px solid var(--acc); background: var(--color-background-secondary); color: var(--color-text-primary); font-weight: 500; }
.card { background: var(--color-background-primary); border: 0.5px solid var(--color-border-tertiary); border-radius: var(--border-radius-lg); padding: 1.2rem; }
.badge { display: inline-flex; align-items: center; padding: 3px 9px; border-radius: 999px; font-size: 11px; font-weight: 500; }
.pf-input { padding: 0.5rem 0.75rem; border: 0.5px solid var(--color-border-secondary); border-radius: var(--border-radius-md); background: var(--color-background-primary); color: var(--color-text-primary); font-size: 13px; outline: none; }
.pf-input:focus { border-color: var(--acc); box-shadow: 0 0 0 2px #F59E0B33; }
.pf-select { padding: 0.5rem 0.75rem; border: 0.5px solid var(--color-border-secondary); border-radius: var(--border-radius-md); background: var(--color-background-primary); color: var(--color-text-primary); font-size: 13px; outline: none; cursor: pointer; }
.btn { padding: 0.45rem 0.9rem; border-radius: var(--border-radius-md); border: 0.5px solid var(--color-border-secondary); background: var(--color-background-primary); color: var(--color-text-primary); font-size: 12.5px; cursor: pointer; display: inline-flex; align-items: center; gap: 5px; transition: background 0.15s; }
.btn:hover { background: var(--color-background-secondary); }
.btn.prime { background: var(--acc); border-color: var(--acc); color: #000; font-weight: 600; }
.btn.prime:hover { filter: brightness(0.92); }
.tbl { width: 100%; border-collapse: collapse; }
.tbl th { padding: 0.65rem 1rem; text-align: left; font-size: 11.5px; font-weight: 500; color: var(--color-text-secondary); border-bottom: 0.5px solid var(--color-border-tertiary); cursor: pointer; user-select: none; white-space: nowrap; }
.tbl th:hover { color: var(--color-text-primary); }
.tbl td { padding: 0.7rem 1rem; font-size: 13px; border-bottom: 0.5px solid var(--color-border-tertiary); color: var(--color-text-primary); }
.tbl tr:last-child td { border-bottom: none; }
.tbl tbody tr:hover td { background: var(--color-background-secondary); }
.shimmer { background: linear-gradient(90deg, var(--color-background-secondary) 25%, var(--color-background-tertiary) 50%, var(--color-background-secondary) 75%); background-size: 200% 100%; animation: shimmer 1.5s infinite; border-radius: 6px; }
@keyframes shimmer { 0% { background-position: 200% 0; } 100% { background-position: -200% 0; } }
.fade-in { animation: fadein 0.25s ease; }
@keyframes fadein { from { opacity: 0; transform: translateY(6px); } to { opacity: 1; transform: translateY(0); } }
`;

function Sidebar({ page, setPage }) {
  const items = [
    { id: "dashboard", Icon: LayoutDashboard, label: "Dashboard" },
    { id: "transactions", Icon: ArrowLeftRight, label: "Transaksi" },
    { id: "reports", Icon: BarChart2, label: "Laporan" },
    { id: "budget", Icon: Wallet, label: "Anggaran" },
    { id: "settings", Icon: Settings, label: "Pengaturan" },
  ];
  const income = TRANSACTIONS.filter(t => t.amount > 0).reduce((s, t) => s + t.amount, 0);
  const expense = TRANSACTIONS.filter(t => t.amount < 0).reduce((s, t) => s + Math.abs(t.amount), 0);
  const pct = Math.round((expense / income) * 100);

  return (
    <aside className="pf-sidebar">
      <div style={{ padding: "0 1.1rem 1.25rem", borderBottom: "0.5px solid var(--color-border-tertiary)" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <div style={{ width: 30, height: 30, borderRadius: 8, background: ACCENT, display: "flex", alignItems: "center", justifyContent: "center" }}>
            <CircleDollarSign size={17} color="#000" strokeWidth={2.5} />
          </div>
          <div>
            <div style={{ fontSize: 14, fontWeight: 700, color: "var(--color-text-primary)", letterSpacing: "-0.3px" }}>FinanceAI</div>
            <div style={{ fontSize: 10.5, color: "var(--color-text-tertiary)" }}>Batam · Mei 2025</div>
          </div>
        </div>
      </div>

      <nav style={{ padding: "0.85rem 0", flex: 1 }}>
        <div style={{ padding: "0 1.1rem 0.5rem", fontSize: 10, fontWeight: 600, color: "var(--color-text-tertiary)", letterSpacing: "0.08em", textTransform: "uppercase" }}>Menu</div>
        {items.map(({ id, Icon, label }) => (
          <div key={id} className={`nav-item${page === id ? " act" : ""}`} onClick={() => setPage(id)}>
            <Icon size={15} strokeWidth={1.8} />
            <span>{label}</span>
          </div>
        ))}
      </nav>

      <div style={{ padding: "0.85rem 1.1rem", borderTop: "0.5px solid var(--color-border-tertiary)" }}>
        <div style={{ fontSize: 10.5, color: "var(--color-text-tertiary)", marginBottom: 6 }}>Rasio Pengeluaran</div>
        <div style={{ height: 5, background: "var(--color-background-secondary)", borderRadius: 99, overflow: "hidden" }}>
          <div style={{ width: `${pct}%`, height: "100%", background: pct > 80 ? "#EF4444" : pct > 60 ? ACCENT : "#10B981", borderRadius: 99, transition: "width 0.5s" }} />
        </div>
        <div style={{ fontSize: 11.5, color: "var(--color-text-secondary)", marginTop: 5 }}>{pct}% dari pemasukan</div>
      </div>

      <div style={{ padding: "0.75rem 1.1rem", borderTop: "0.5px solid var(--color-border-tertiary)" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <div style={{ width: 28, height: 28, borderRadius: "50%", background: ACCENT + "28", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 700, color: ACCENT }}>U</div>
          <div>
            <div style={{ fontSize: 12.5, fontWeight: 500, color: "var(--color-text-primary)" }}>User</div>
            <div style={{ fontSize: 10.5, color: "var(--color-text-tertiary)" }}>user@email.com</div>
          </div>
        </div>
      </div>
    </aside>
  );
}

function SummaryCard({ label, amount, change, pos, Icon, color }) {
  return (
    <div className="card fade-in">
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 10 }}>
        <span style={{ fontSize: 12, color: "var(--color-text-secondary)", fontWeight: 500 }}>{label}</span>
        <div style={{ width: 28, height: 28, borderRadius: 7, background: color + "22", display: "flex", alignItems: "center", justifyContent: "center" }}>
          <Icon size={14} color={color} strokeWidth={2} />
        </div>
      </div>
      <div style={{ fontSize: 20, fontWeight: 700, color: "var(--color-text-primary)", letterSpacing: "-0.8px", marginBottom: 6 }}>{fmtIDR(amount)}</div>
      <div style={{ fontSize: 11.5, color: pos ? "#10B981" : "#EF4444", display: "flex", alignItems: "center", gap: 3 }}>
        {pos ? <TrendingUp size={12} /> : <TrendingDown size={12} />}
        <span>{change} vs bulan lalu</span>
      </div>
    </div>
  );
}

function DonutChart({ data }) {
  const ref = useRef(null);
  const chart = useRef(null);

  useEffect(() => {
    if (!ref.current || !data.length) return;
    const dark = window.matchMedia("(prefers-color-scheme: dark)").matches;
    if (chart.current) chart.current.destroy();
    chart.current = new Chart(ref.current, {
      type: "doughnut",
      data: {
        labels: data.map(d => d.label),
        datasets: [{
          data: data.map(d => d.value),
          backgroundColor: data.map(d => d.color),
          borderColor: dark ? "#1a1a2e" : "#ffffff",
          borderWidth: 3,
          hoverOffset: 8,
        }],
      },
      options: {
        responsive: true, maintainAspectRatio: false, cutout: "74%",
        plugins: {
          legend: { display: false },
          tooltip: { callbacks: { label: (c) => ` ${c.label}: ${fmtIDR(c.raw)}` } },
        },
      },
    });
    return () => { if (chart.current) { chart.current.destroy(); chart.current = null; } };
  }, [data]);

  const total = data.reduce((s, d) => s + d.value, 0);

  return (
    <div style={{ position: "relative" }}>
      <div style={{ position: "relative", height: 188 }}>
        <canvas ref={ref} role="img" aria-label="Donat chart distribusi pengeluaran">Distribusi pengeluaran per kategori</canvas>
        <div style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%,-50%)", textAlign: "center", pointerEvents: "none" }}>
          <div style={{ fontSize: 10, color: "var(--color-text-tertiary)", fontWeight: 500 }}>TOTAL</div>
          <div style={{ fontSize: 14, fontWeight: 700, color: "var(--color-text-primary)", letterSpacing: "-0.5px", marginTop: 2 }}>{fmtIDR(total)}</div>
        </div>
      </div>
      <div style={{ display: "flex", flexWrap: "wrap", gap: "6px 14px", marginTop: 14 }}>
        {data.map(d => (
          <div key={d.label} style={{ display: "flex", alignItems: "center", gap: 5, fontSize: 11 }}>
            <div style={{ width: 7, height: 7, borderRadius: 2, background: d.color, flexShrink: 0 }} />
            <span style={{ color: "var(--color-text-secondary)" }}>{d.label}</span>
            <span style={{ color: "var(--color-text-tertiary)" }}>({Math.round((d.value / total) * 100)}%)</span>
          </div>
        ))}
      </div>
    </div>
  );
}

function AIInsights({ transactions }) {
  const [text, setText] = useState("");
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState("");

  const run = useCallback(async () => {
    setLoading(true); setErr(""); setText("");
    try {
      // Endpoint Python Flask lokalmu nanti
      const res = await fetch("http://localhost:5000/api/ai", { method: "POST" });
      const data = await res.json();
      setText(data.insight || "Tidak ada respons.");
    } catch {
      setErr("Gagal terhubung ke AI. Pastikan backend Flask sudah dinyalakan.");
    } finally {
      setLoading(false);
    }
  }, []);

  return (
    <div className="card" style={{ display: "flex", flexDirection: "column", height: "100%" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 14 }}>
        <div>
          <div style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 13.5, fontWeight: 600, color: "var(--color-text-primary)" }}>
            <Sparkles size={14} color={ACCENT} />
            AI Insights
          </div>
          <div style={{ fontSize: 11.5, color: "var(--color-text-tertiary)", marginTop: 3 }}>Analisis cerdas keuangan Anda</div>
        </div>
        <button className="btn prime" onClick={run} disabled={loading} style={{ fontSize: 12 }}>
          <Sparkles size={12} />
          {loading ? "Memproses..." : "Analisis"}
        </button>
      </div>

      {loading && (
        <div style={{ flex: 1, display: "flex", flexDirection: "column", gap: 8, paddingTop: 4 }}>
          {[85, 72, 90, 60].map((w, i) => (
            <div key={i} className="shimmer" style={{ height: 11, width: `${w}%` }} />
          ))}
        </div>
      )}

      {!loading && !text && !err && (
        <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 8, color: "var(--color-text-tertiary)", paddingBottom: 8 }}>
          <div style={{ width: 40, height: 40, borderRadius: "50%", background: ACCENT + "18", display: "flex", alignItems: "center", justifyContent: "center" }}>
            <Sparkles size={18} color={ACCENT} />
          </div>
          <div style={{ textAlign: "center", fontSize: 12.5, lineHeight: 1.6 }}>
            Klik <strong style={{ color: "var(--color-text-secondary)" }}>Analisis</strong> untuk mendapatkan<br />rekomendasi keuangan AI
          </div>
        </div>
      )}

      {err && <div style={{ color: "#EF4444", fontSize: 13 }}>{err}</div>}

      {text && (
        <div className="fade-in" style={{ fontSize: 13, lineHeight: 1.75, color: "var(--color-text-primary)", whiteSpace: "pre-wrap", flex: 1 }}>
          {text}
        </div>
      )}
    </div>
  );
}

function DashboardPage() {
  const income = TRANSACTIONS.filter(t => t.amount > 0).reduce((s, t) => s + t.amount, 0);
  const expense = TRANSACTIONS.filter(t => t.amount < 0).reduce((s, t) => s + Math.abs(t.amount), 0);
  const balance = income - expense;

  const donutData = Object.entries(
    TRANSACTIONS.filter(t => t.amount < 0).reduce((a, t) => { a[t.cat] = (a[t.cat] || 0) + Math.abs(t.amount); return a; }, {})
  ).map(([cat, value]) => ({ label: CAT_LABELS[cat], value, color: CAT_COLORS[cat] })).sort((a, b) => b.value - a.value);

  const recent = [...TRANSACTIONS].sort((a, b) => new Date(b.date) - new Date(a.date)).slice(0, 5);

  return (
    <div className="fade-in">
      <div style={{ marginBottom: "1.5rem" }}>
        <h1 style={{ fontSize: 21, fontWeight: 700, color: "var(--color-text-primary)", letterSpacing: "-0.5px" }}>Dashboard</h1>
        <p style={{ fontSize: 13, color: "var(--color-text-secondary)", marginTop: 3 }}>Ringkasan keuangan Anda · Mei 2026</p>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 14, marginBottom: 18 }}>
        <SummaryCard label="Total Pemasukan" amount={income} change="+12.4%" pos={true} Icon={TrendingUp} color="#10B981" />
        <SummaryCard label="Total Pengeluaran" amount={expense} change="+3.2%" pos={false} Icon={TrendingDown} color="#EF4444" />
        <SummaryCard label="Saldo Bersih" amount={balance} change="+8.7%" pos={true} Icon={CircleDollarSign} color={ACCENT} />
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, marginBottom: 18 }}>
        <div className="card">
          <div style={{ fontSize: 13.5, fontWeight: 600, color: "var(--color-text-primary)", marginBottom: 2 }}>Distribusi Pengeluaran</div>
          <div style={{ fontSize: 11.5, color: "var(--color-text-tertiary)", marginBottom: 14 }}>Per kategori · bulan ini</div>
          <DonutChart data={donutData} />
        </div>
        <AIInsights transactions={TRANSACTIONS} />
      </div>

      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ padding: "0.9rem 1.1rem", borderBottom: "0.5px solid var(--color-border-tertiary)", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <span style={{ fontSize: 13.5, fontWeight: 600, color: "var(--color-text-primary)" }}>Transaksi Terbaru</span>
          <span style={{ fontSize: 11.5, color: "var(--color-text-tertiary)" }}>5 terakhir</span>
        </div>
        <table className="tbl">
          <thead>
            <tr>
              <th>Tanggal</th>
              <th>Keterangan</th>
              <th>Kategori</th>
              <th style={{ textAlign: "right" }}>Jumlah</th>
            </tr>
          </thead>
          <tbody>
            {recent.map(t => (
              <tr key={t.id}>
                <td style={{ color: "var(--color-text-secondary)", whiteSpace: "nowrap", fontSize: 12 }}>{fmtDate(t.date)}</td>
                <td style={{ maxWidth: 180 }}>{t.desc}</td>
                <td><span className="badge" style={{ background: CAT_COLORS[t.cat] + "22", color: CAT_COLORS[t.cat] }}>{CAT_LABELS[t.cat]}</span></td>
                <td style={{ textAlign: "right", fontWeight: 600, color: t.amount > 0 ? "#10B981" : "var(--color-text-primary)", fontVariantNumeric: "tabular-nums" }}>
                  {t.amount > 0 ? "+" : ""}{fmtIDR(t.amount)}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function TransactionsPage() {
  const [q, setQ] = useState("");
  const [cat, setCat] = useState("all");
  const [sk, setSk] = useState("date");
  const [sd, setSd] = useState("desc");

  const sort = (key) => { if (sk === key) setSd(d => d === "asc" ? "desc" : "asc"); else { setSk(key); setSd("desc"); } };

  const rows = TRANSACTIONS
    .filter(t => cat === "all" || t.cat === cat)
    .filter(t => t.desc.toLowerCase().includes(q.toLowerCase()))
    .sort((a, b) => {
      let va = a[sk], vb = b[sk];
      if (sk === "date") { va = new Date(va); vb = new Date(vb); }
      if (sk === "amount") { va = Math.abs(va); vb = Math.abs(vb); }
      return sd === "asc" ? (va > vb ? 1 : -1) : (va < vb ? 1 : -1);
    });

  const SortIco = ({ k }) => {
    if (sk !== k) return <ChevronsUpDown size={11} style={{ opacity: 0.4, verticalAlign: "middle", marginLeft: 3 }} />;
    return sd === "asc"
      ? <ChevronUp size={11} style={{ verticalAlign: "middle", marginLeft: 3, color: ACCENT }} />
      : <ChevronDown size={11} style={{ verticalAlign: "middle", marginLeft: 3, color: ACCENT }} />;
  };

  return (
    <div className="fade-in">
      <div style={{ marginBottom: "1.5rem" }}>
        <h1 style={{ fontSize: 21, fontWeight: 700, color: "var(--color-text-primary)", letterSpacing: "-0.5px" }}>Transaksi</h1>
        <p style={{ fontSize: 13, color: "var(--color-text-secondary)", marginTop: 3 }}>Riwayat semua transaksi keuangan</p>
      </div>

      <div style={{ display: "flex", gap: 8, marginBottom: 14, flexWrap: "wrap" }}>
        <input className="pf-input" placeholder="🔍  Cari transaksi..." value={q} onChange={e => setQ(e.target.value)} style={{ flex: 1, minWidth: 180 }} />
        <select className="pf-select" value={cat} onChange={e => setCat(e.target.value)}>
          <option value="all">Semua Kategori</option>
          {Object.entries(CAT_LABELS).map(([k, v]) => <option key={k} value={k}>{v}</option>)}
        </select>
        <button className="btn" onClick={() => { setQ(""); setCat("all"); }}><RotateCcw size={13} /> Reset</button>
        <button className="btn prime"><Plus size={13} /> Tambah</button>
      </div>

      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ padding: "0.75rem 1.1rem", borderBottom: "0.5px solid var(--color-border-tertiary)", display: "flex", gap: 10, alignItems: "center" }}>
          <span style={{ fontSize: 12, color: "var(--color-text-tertiary)" }}>{rows.length} transaksi ditemukan</span>
          <div style={{ flex: 1 }} />
          <span style={{ fontSize: 11.5, color: "#10B981", fontWeight: 500 }}>
            ↑ {fmtIDR(rows.filter(t => t.amount > 0).reduce((s,t)=>s+t.amount,0))}
          </span>
          <span style={{ fontSize: 11.5, color: "#EF4444", fontWeight: 500 }}>
            ↓ {fmtIDR(rows.filter(t => t.amount < 0).reduce((s,t)=>s+Math.abs(t.amount),0))}
          </span>
        </div>
        <table className="tbl">
          <thead>
            <tr>
              <th onClick={() => sort("date")}>Tanggal <SortIco k="date" /></th>
              <th onClick={() => sort("desc")}>Keterangan <SortIco k="desc" /></th>
              <th>Kategori</th>
              <th onClick={() => sort("amount")} style={{ textAlign: "right" }}>Jumlah <SortIco k="amount" /></th>
              <th style={{ textAlign: "right" }}>Tipe</th>
            </tr>
          </thead>
          <tbody>
            {rows.map(t => (
              <tr key={t.id}>
                <td style={{ color: "var(--color-text-secondary)", fontSize: 12, whiteSpace: "nowrap" }}>{fmtDate(t.date)}</td>
                <td>{t.desc}</td>
                <td><span className="badge" style={{ background: CAT_COLORS[t.cat] + "22", color: CAT_COLORS[t.cat] }}>{CAT_LABELS[t.cat]}</span></td>
                <td style={{ textAlign: "right", fontWeight: 700, color: t.amount > 0 ? "#10B981" : "#EF4444", fontVariantNumeric: "tabular-nums" }}>
                  {t.amount > 0 ? "+" : ""}{fmtIDR(t.amount)}
                </td>
                <td style={{ textAlign: "right" }}>
                  <span className="badge" style={{ background: t.amount > 0 ? "#10B98120" : "#EF444420", color: t.amount > 0 ? "#10B981" : "#EF4444" }}>
                    {t.amount > 0 ? "Pemasukan" : "Pengeluaran"}
                  </span>
                </td>
              </tr>
            ))}
            {!rows.length && (
              <tr><td colSpan={5} style={{ textAlign: "center", padding: "2.5rem", color: "var(--color-text-tertiary)", fontSize: 13 }}>Tidak ada transaksi ditemukan</td></tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function Placeholder({ title, Icon }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", minHeight: 400, gap: 10, color: "var(--color-text-tertiary)" }}>
      <div style={{ width: 52, height: 52, borderRadius: 14, background: "var(--color-background-secondary)", display: "flex", alignItems: "center", justifyContent: "center" }}>
        <Icon size={22} strokeWidth={1.5} />
      </div>
      <div style={{ fontSize: 15, fontWeight: 500, color: "var(--color-text-secondary)" }}>{title}</div>
      <div style={{ fontSize: 12.5 }}>Fitur ini segera hadir</div>
    </div>
  );
}

export default function App() {
  const [page, setPage] = useState("dashboard");

  const content = {
    dashboard: <DashboardPage />,
    transactions: <TransactionsPage />,
    reports: <Placeholder title="Laporan" Icon={BarChart2} />,
    budget: <Placeholder title="Anggaran" Icon={Wallet} />,
    settings: <Placeholder title="Pengaturan" Icon={Settings} />,
  };

  return (
    <>
      <style>{CSS}</style>
      <div className="pf-wrap">
        <Sidebar page={page} setPage={setPage} />
        <main className="pf-main">{content[page]}</main>
      </div>
    </>
  );
}
